/**
 * useSignalTier — Signal delivery tier logic for scanners & alerts
 *
 * Tier hierarchy (mapped from useTierGate):
 *   explorer (free)  → 15-min delay, top 5 signals, 3 alerts
 *   trader           → 5-min delay, top 20 signals, 50 alerts
 *   pro+             → real-time, unlimited signals, unlimited alerts
 */
import { useMemo } from 'react';
import { getUserTier } from './useTierGate';

// Signal delivery config per tier
const SIGNAL_TIERS = {
  explorer: {
    delayMinutes: 15,
    delayLabel: 'DELAYED',
    delayColor: '#D29922',         // amber
    badgeBg: 'rgba(210,153,34,0.15)',
    maxSignals: 5,
    maxAlerts: 3,
    canViewAnalysis: false,
  },
  trader: {
    delayMinutes: 5,
    delayLabel: 'NEAR REAL-TIME',
    delayColor: '#60A5FA',         // blue
    badgeBg: 'rgba(96,165,250,0.15)',
    maxSignals: 20,
    maxAlerts: 50,
    canViewAnalysis: true,
  },
  pro: {
    delayMinutes: 0,
    delayLabel: 'LIVE',
    delayColor: '#22C55E',         // green
    badgeBg: 'rgba(34,197,94,0.15)',
    maxSignals: Infinity,
    maxAlerts: Infinity,
    canViewAnalysis: true,
  },
  institutional: {
    delayMinutes: 0,
    delayLabel: 'LIVE',
    delayColor: '#22C55E',
    badgeBg: 'rgba(34,197,94,0.15)',
    maxSignals: Infinity,
    maxAlerts: Infinity,
    canViewAnalysis: true,
  },
};

/**
 * Map the resolved tier to signal tier config.
 * pro / institutional / developer all get "pro" signal tier.
 */
function resolveSignalTier(userTier) {
  if (SIGNAL_TIERS[userTier]) return SIGNAL_TIERS[userTier];
  // Any tier >= pro gets full access
  if (['pro', 'institutional', 'developer', 'elite'].includes(userTier)) {
    return SIGNAL_TIERS.pro;
  }
  return SIGNAL_TIERS.explorer;
}

export default function useSignalTier() {
  const userTier = getUserTier();

  return useMemo(() => {
    const config = resolveSignalTier(userTier);
    const isDelayed = config.delayMinutes > 0;
    const isLive = config.delayMinutes === 0;

    return {
      userTier,
      ...config,
      isDelayed,
      isLive,

      /**
       * Apply signal count limit to an array of signals.
       * Returns { visible, hidden, total }
       */
      applyLimit(signals) {
        if (!signals || !Array.isArray(signals)) {
          return { visible: [], hidden: 0, total: 0 };
        }
        const total = signals.length;
        const visible = config.maxSignals >= total
          ? signals
          : signals.slice(0, config.maxSignals);
        const hidden = Math.max(0, total - config.maxSignals);
        return { visible, hidden, total };
      },

      /**
       * Check if the user can create more alerts.
       * Returns { allowed, current, max, remaining }
       */
      checkAlertLimit(currentCount) {
        const max = config.maxAlerts;
        const remaining = Math.max(0, max - currentCount);
        return {
          allowed: currentCount < max,
          current: currentCount,
          max: max === Infinity ? 'Unlimited' : max,
          remaining: max === Infinity ? Infinity : remaining,
          isUnlimited: max === Infinity,
        };
      },
    };
  }, [userTier]);
}

export { SIGNAL_TIERS, resolveSignalTier };
